def validate(args, output):
    n, k = args[0], args[1]
    if not isinstance(output, list) or len(output) != k:
        return False
    prod = 1
    for x in output:
        if not isinstance(x, int) or x < 1:
            return False
        prod *= x
    if prod != n:
        return False
    out_diff = max(output) - min(output)
    best = [float('inf')]
    def search(rem, kl, start, lo, hi):
        if kl == 1:
            f = rem
            if f >= start:
                d = max(hi, f) - min(lo, f)
                if d < best[0]:
                    best[0] = d
            return
        d = start
        while d ** kl <= rem:
            if rem % d == 0:
                search(rem // d, kl - 1, d, min(lo, d), max(hi, d))
            d += 1
    search(n, k, 1, n, 1)
    return out_diff == best[0]

