function validate(args, output) {
    const n = args[0], k = args[1];
    if (!Array.isArray(output) || output.length !== k) return false;
    let prod = 1;
    for (const x of output) {
        if (!Number.isInteger(x) || x < 1) return false;
        prod *= x;
    }
    if (prod !== n) return false;
    const outDiff = Math.max(...output) - Math.min(...output);
    let best = Infinity;
    function search(rem, kl, start, lo, hi) {
        if (kl === 1) {
            const f = rem;
            if (f >= start) {
                const d = Math.max(hi, f) - Math.min(lo, f);
                if (d < best) best = d;
            }
            return;
        }
        let d = start;
        while (Math.pow(d, kl) <= rem) {
            if (rem % d === 0) search(rem / d, kl - 1, d, Math.min(lo, d), Math.max(hi, d));
            d += 1;
        }
    }
    search(n, k, 1, n, 1);
    return outDiff === best;
}

