class Solution:
    def minDifference(self, n, k):
        best = [None, float('inf')]
        def rec(rem, kl, cur):
            if kl == 0:
                if rem == 1:
                    s = sorted(cur)
                    diff = s[-1] - s[0]
                    if diff < best[1] or (diff == best[1] and (best[0] is None or s < best[0])):
                        best[1] = diff
                        best[0] = s
                return
            start = cur[-1] if cur else 1
            for d in range(start, rem + 1):
                if rem % d == 0:
                    rec(rem // d, kl - 1, cur + [d])
        rec(n, k, [])
        return best[0]

