        best = [None]
        def rec(remaining, k_left, start, cur):
            if k_left == 1:
                f = remaining
                if f < start:
                    return
                split = cur + [f]
                diff = split[-1] - split[0]
                if diff < best_diff[0] or (diff == best_diff[0] and (best[0] is None or split < best[0])):
                    best_diff[0] = diff
                    best[0] = split[:]
                return
            d = start
            while d ** k_left <= remaining:
                if remaining % d == 0:
                    rec(remaining // d, k_left - 1, d, cur + [d])
                d += 1
        rec(n, k, 1, [])
        return best[0]

