var minDifference = function(n, k) {
    let bestDiff = Infinity, best = null;
    const lessThan = (a, b) => {
        const m = Math.min(a.length, b.length);
        for (let i = 0; i < m; i++) if (a[i] !== b[i]) return a[i] < b[i];
        return a.length < b.length;
    };
    function rec(remaining, kLeft, start, cur) {
        if (kLeft === 1) {
            const f = remaining;
            if (f < start) return;
            const split = cur.concat([f]);
            const diff = split[split.length - 1] - split[0];
            if (diff < bestDiff || (diff === bestDiff && (best === null || lessThan(split, best)))) {
                bestDiff = diff;
                best = split.slice();
            }
            return;
        }
        let d = start;
        while (Math.pow(d, kLeft) <= remaining) {
            if (remaining % d === 0) rec(remaining / d, kLeft - 1, d, cur.concat([d]));
            d += 1;
        }
    }
    rec(n, k, 1, []);
    return best;
};
